const COLUMN_DDL = [
  // Indexes for performance
  { ddl: `CREATE INDEX ENG_SOL_FILIAL_IDX ON ENG_SOLICITACAO(CODFILIAL)` },
  { ddl: `CREATE INDEX ENG_SOL_STATUS_IDX ON ENG_SOLICITACAO(STATUS)` },
  { ddl: `CREATE INDEX ENG_OS_FILIAL_IDX ON ENG_ORDEM_SERVICO(CODFILIAL)` },
  { ddl: `CREATE INDEX ENG_OS_STATUS_IDX ON ENG_ORDEM_SERVICO(STATUS)` },
  { ddl: `CREATE INDEX ENG_OS_NUM_IDX ON ENG_ORDEM_SERVICO(NUMERO)` },
  { ddl: `CREATE INDEX ENG_ATIVO_COD_IDX ON ENG_ATIVO(CODIGO)` },
  { ddl: `CREATE INDEX ENG_ESTITEM_EST_IDX ON ENG_ESTOQUE_ITEM(ESTOQUE_ID)` },
  { ddl: `CREATE INDEX ENG_ESTMOV_ITEM_IDX ON ENG_ESTOQUE_MOV(ITEM_ID)` },
  { ddl: `CREATE INDEX ENG_OSHIST_OS_IDX ON ENG_OS_HISTORICO(OS_ID)` },
  { ddl: `CREATE INDEX ENG_PREST_CNPJ_IDX ON ENG_PRESTADOR(CNPJ)` },
  { ddl: `CREATE INDEX ENG_PT_OS_IDX ON ENG_PERMISSAO_TRABALHO(OS_ID)` },
];

export async function ensureEngenhariaTables() {
  if (initialized) return;
  for (const t of TABLE_DDL) {
    try {
      await execDml(t.ddl);
    } catch (e) {
      if (e?.errorNum !== 955) {
        // 955 = table already exists - ok
        // 2264 = constraint already exists - ok
        if (e?.errorNum !== 2264) {
          console.warn(`ensureEngenhariaTables [${t.name}]:`, e?.code || e?.message);
        }
      }
    }
  }
  for (const c of COLUMN_DDL) {
    try {
      await execDml(c.ddl);
    } catch (_) {
      // index may already exist
    }
  }
  initialized = true;
}
